onClick:
{{
  !EmailInput.text || !FirstNameInput.text || !LastNameInput.text || !createpasswordinput.text || !PasswordInput.text
    ? showAlert("Please fill in all required fields", "warning")
    : createpasswordinput.text !== PasswordInput.text
      ? showAlert("Passwords do not match", "error")
      : !Checkbox.isChecked
        ? showAlert("Please agree to the terms of use", "warning")
        : CreateUserProfile.run()
            .then((res) => {
              if (res?.id) {
                storeValue("profileId", res.id);
              }
              showAlert("Account created successfully", "success");
              navigateTo("Homepage");
            })
            .catch((error) => {
              showAlert("Failed to create account", "error");
              console.log(error);
            });
}}
